function normalizePath(filePath){let startIndex=0;let endIndex=filePath.length;if(/[a-z]:\//i.test(filePath)){startIndex=3;}
if(filePath.startsWith("./")){startIndex=2;}
if(filePath.startsWith("/")){startIndex=1;}
if(filePath.endsWith("/")){endIndex=filePath.length-1;}
return filePath.slice(startIndex,endIndex).replace(/\\/g,"/");}
function assertValidName(name){if(typeof name!=="string"){throw new TypeError("name must be a string");}
if(!name){throw new TypeError("name cannot be empty");}
if(name==="."){throw new TypeError(`name cannot be "."`);}
if(name===".."){throw new TypeError(`name cannot be ".."`);}
if(name.includes("/")||name.includes("\\")){throw new TypeError(`name cannot contain a slash or backslash: "${name}"`,);}}
export class Path{#steps;constructor(steps=[]){if(typeof steps[Symbol.iterator]!=="function"){throw new TypeError("steps must be iterable");}
this.#steps=[...steps];this.#steps.forEach(assertValidName);}
push(...steps){steps.forEach(assertValidName);this.#steps.push(...steps);}
pop(){return this.#steps.pop();}
steps(){return this.#steps.values();}
[Symbol.iterator](){return this.steps();}
get name(){return this.#steps[this.#steps.length-1];}
set name(value){assertValidName(value);this.#steps[this.#steps.length-1]=value;}
get size(){return this.#steps.length;}
toString(){return this.#steps.join("/");}
static from(pathish){if(typeof pathish==="string"){if(!pathish){throw new TypeError("argument cannot be empty");}
return Path.fromString(pathish);}
if(pathish instanceof URL){return Path.fromURL(pathish);}
if(pathish instanceof Path||Array.isArray(pathish)){return new Path(pathish);}
throw new TypeError("argument must be a string, URL, Path, or Array");}
static fromString(fileOrDirPath){return new Path(normalizePath(fileOrDirPath).split("/"));}
static fromURL(url){if(!(url instanceof URL)){throw new TypeError("url must be a URL instance");}
if(!url.pathname||url.pathname==="/"){throw new TypeError("url.pathname cannot be empty");}
if(url.protocol!=="file:"){throw new TypeError(`url.protocol must be "file:"`);}
return new Path(normalizePath(url.pathname.slice(1)).split("/"));}}